   277→function areSame(fromExtension: ISyncExtension, toExtension: ISyncExtension, checkVersionProperty: boolean, checkInstalledProperty: boolean): boolean {
   278→	if (fromExtension.disabled !== toExtension.disabled) {
   279→		/* extension enablement changed */
   280→		return false;
   281→	}
   282→
   283→	if (!!fromExtension.isApplicationScoped !== !!toExtension.isApplicationScoped) {
   284→		/* extension application scope has changed */
   285→		return false;
   286→	}
   287→
   288→	if (checkInstalledProperty && fromExtension.installed !== toExtension.installed) {
   289→		/* extension installed property changed */
   290→		return false;
   291→	}
   292→
   293→	if (fromExtension.installed && toExtension.installed) {
   294→
   295→		if (fromExtension.preRelease !== toExtension.preRelease) {
   296→			/* installed extension's pre-release version changed */
   297→			return false;
   298→		}
   299→
   300→		if (fromExtension.pinned !== toExtension.pinned) {
   301→			/* installed extension's pinning changed */
   302→			return false;
   303→		}
   304→
   305→		if (toExtension.pinned && fromExtension.version !== toExtension.version) {
   306→			/* installed extension's pinned version changed */
   307→			return false;
   308→		}
   309→	}
   310→
   311→	if (!isSameExtensionState(fromExtension.state, toExtension.state)) {
   312→		/* extension state changed */
   313→		return false;
   314→	}
   315→
   316→	if ((checkVersionProperty && fromExtension.version !== toExtension.version)) {
   317→		/* extension version changed */
   318→		return false;
   319→	}
   320→
   321→	return true;
   322→}
