   335→	if (localState && semver.gt(localExtension.version, remoteExtension.version)) {
   336→		return localState;
   337→	}
   338→	// If remote state exists and remote extension is latest, use remote state
   339→	if (remoteState && semver.gt(remoteExtension.version, localExtension.version)) {
   340→		return remoteState;
   341→	}
   342→
   343→
   344→	/* Remote and local are on same version */
   345→
   346→	// If local state is not yet set, use remote state
   347→	if (!localState) {
   348→		return remoteState;
   349→	}
   350→	// If remote state is not yet set, use local state
   351→	if (!remoteState) {
   352→		return localState;
   353→	}
