   398→// massage incoming extension - add optional properties
   399→function massageIncomingExtension(extension: ISyncExtension): ISyncExtension {
   400→	return { ...extension, ...{ disabled: !!extension.disabled, installed: !!extension.installed } };
   401→}
   402→
   403→// massage outgoing extension - remove optional properties
   404→function massageOutgoingExtension(extension: ISyncExtension, key: string): ISyncExtension {
   405→	const massagedExtension: ISyncExtension = {
   406→		...extension,
   407→		identifier: {
   408→			id: extension.identifier.id,
   409→			uuid: key.startsWith('uuid:') ? key.substring('uuid:'.length) : undefined
