   411→		/* set following always so that to differentiate with older clients */
   412→		preRelease: !!extension.preRelease,
   413→		pinned: !!extension.pinned,
   414→	};
   415→	if (!extension.disabled) {
   416→		delete massagedExtension.disabled;
   417→	}
   418→	if (!extension.installed) {
   419→		delete massagedExtension.installed;
   420→	}
   421→	if (!extension.state) {
   422→		delete massagedExtension.state;
   423→	}
   424→	if (!extension.isApplicationScoped) {
   425→		delete massagedExtension.isApplicationScoped;
   426→	}
   427→	return massagedExtension;
   428→}
